INSERT INTO explore_bosses (code,name,title,region,place,gender,age,workout_label,difficulty_stars,quote,skill_name,skill_desc,dialogue_intro,dialogue_start,scene_image_url,card_image_url,lat,lng,radius_m,reward_exp,reward_dp,retry_dp_cost,workout_kind,segments,data_source,display_order,enabled) VALUES
('DOR-TPE-001','大安小鹿','大安的傳說級守門人','臺北市·大安區','大安森林公園','女',39,'節奏跑混合型',5,'「蟬都叫成這樣了，你還不加速？」','樹影瞬移','樹影瞬移：大安小鹿的招牌絕技，讓挑戰者措手不及。','你完成打卡時，大安小鹿才和麻雀打完招呼，接著把視線轉向新玩家。<br>大安小鹿：「欸，等一下。這個陌生ID是你的？想讓我閉嘴還是想被我記住？」<br>大安小鹿：「我先把話放這裡：前半先別把所有招式交光，再沿路線跑到終點提示出現。做得到算你有本事；半路裝忙，我可以笑你笑到收操。」<br>挑戰視窗停在確認頁。<user_nickname>，要接受大安小鹿的叫陣嗎？<br>','大安小鹿：「「蟬都叫成這樣了，你還不加速？」」','','',25.03342,121.5352,120,100,25,0,'tempo','[{"kind":"warmup","label":"暖身","target_type":"distance","target":1500,"pace_fast_s":399,"pace_slow_s":429,"reps":1,"rest_s":0},{"kind":"work","label":"節奏跑","target_type":"distance","target":5000,"pace_fast_s":306,"pace_slow_s":336,"reps":1,"rest_s":0},{"kind":"cooldown","label":"緩和","target_type":"distance","target":1000,"pace_fast_s":399,"pace_slow_s":429,"reps":1,"rest_s":0}]'::jsonb,'gps',1,TRUE),
('DOR-TPE-002','台北阿衝','台北的封面級關主','臺北市·松山區','臺北田徑場','男',27,'間歇衝刺型',5,'「你可以慢，但不能亂跑道。」','彎道切線','彎道切線：台北阿衝的招牌絕技，讓挑戰者措手不及。','你一完成打卡，台北阿衝就笑了；很難判斷是看到對手，還是又想到爛梗。<br>台北阿衝：「喂，先別走。誰把你放進這張地圖的？想挑戰配速還是現場氣氛？」<br>台北阿衝：「我的笑話可能零分，配速不會。先記好：快段要快得有誠意，然後完成三輪快慢交替。你若輸了，記得笑一下表示有禮貌。」<br>對戰入口已經開啟。<user_nickname>，要接受台北阿衝的叫陣嗎？<br>','台北阿衝：「「你可以慢，但不能亂跑道。」」','','',25.04955,121.55186,140,100,25,0,'interval','[{"kind":"warmup","label":"暖身","target_type":"distance","target":1500,"pace_fast_s":399,"pace_slow_s":429,"reps":1,"rest_s":0},{"kind":"work","label":"800m 間歇","target_type":"distance","target":800,"pace_fast_s":255,"pace_slow_s":285,"reps":6,"rest_s":120},{"kind":"cooldown","label":"緩和","target_type":"distance","target":1000,"pace_fast_s":399,"pace_slow_s":429,"reps":1,"rest_s":0}]'::jsonb,'gps',2,TRUE),
('DOR-TPE-003','椰林阿彎','椰林的主線王座關主','臺北市·大安區','國立臺灣大學田徑場','女',34,'節奏跑加速型',5,'「跑道不會騙人啦，秒數都寫在腿上。」','白線幻影','白線幻影：椰林阿彎的招牌絕技，讓挑戰者措手不及。','椰林阿彎替跑道多畫了一條線，轉身便宣布你已經越界進副本。<br>椰林阿彎：「哎唷，新玩家喔？名字先報一下，想在沒坡的地方當今天唯一難度？」<br>椰林阿彎：「我看到平路會想睡，看到對手才會醒。任務就三步：先按路線跑，別自己加戲；沿路線跑到終點提示出現；別讓最後一步拖累前面，別讓我又切回省電。」<br>倒數鍵正在閃。<user_nickname>，要接受椰林阿彎的叫陣嗎？<br>','椰林阿彎：「「跑道不會騙人啦，秒數都寫在腿上。」」','','',25.01842,121.53659,130,100,25,0,'variable','[{"kind":"warmup","label":"暖身","target_type":"distance","target":1200,"pace_fast_s":399,"pace_slow_s":429,"reps":1,"rest_s":0},{"kind":"surge","label":"變速跑 快段 1K","target_type":"distance","target":1000,"pace_fast_s":267,"pace_slow_s":297,"reps":8,"rest_s":120},{"kind":"cooldown","label":"緩和","target_type":"distance","target":1000,"pace_fast_s":399,"pace_slow_s":429,"reps":1,"rest_s":0}]'::jsonb,'gps',3,TRUE),
('DOR-TPE-004','福和阿堤','福和的全城壓軸Boss','臺北市·中正區','福和橋河濱／寶藏巖國手之道','男',41,'長距離巡航型',5,'「折返點到了？很好，回程才是本體。」','水岸巡航','水岸巡航：福和阿堤的招牌絕技，讓挑戰者措手不及。','你完成打卡時，福和阿堤正把河濱地圖折回腰包，像早知道你會出現。<br>福和阿堤：「站住。我的對手名單沒有你，想多加一組還是少一個藉口？」<br>福和阿堤：「我看到直線就想加速，看到你就想多加一組。任務就三步：倒數歸零就別再找狀態；把每組速度維持到提示結束；倒數結束前都算戰鬥時間，今天這組算你自己送上門。」<br>任務板多了一張挑戰單。<user_nickname>，要接受福和阿堤的叫陣嗎？<br>','福和阿堤：「「折返點到了？很好，回程才是本體。」」','','',25.0122,121.5356,200,100,25,0,'interval','[{"kind":"warmup","label":"暖身","target_type":"distance","target":1500,"pace_fast_s":399,"pace_slow_s":429,"reps":1,"rest_s":0},{"kind":"work","label":"2000m 間歇","target_type":"distance","target":2000,"pace_fast_s":273,"pace_slow_s":303,"reps":3,"rest_s":200},{"kind":"cooldown","label":"緩和","target_type":"distance","target":1000,"pace_fast_s":399,"pace_slow_s":429,"reps":1,"rest_s":0}]'::jsonb,'gps',4,TRUE),
('DOR-TPE-005','中山小颱風','大佳的傳說級守門人','臺北市·中山區','大佳河濱公園','女',29,'耐力折返型',5,'「橋下陰影是補給，不是休息藉口。」','夜燈導航','夜燈導航：中山小颱風的招牌絕技，讓挑戰者措手不及。','中山小颱風從橋下陰影走出來，熟門熟路得像首領專屬登場點。<br>中山小颱風：「蛤？這區什麼時候多了你這號人物？想跟太陽拚還是跟我拚？」<br>中山小颱風：「今天熱歸熱，任務照跑。沿任務線跑到終端點再返程；呼吸可以亂，路線不能少，別只會在陰影裡點打卡。」<br>中山小颱風：「稱號欄還空著，能不能拿走看你這一趟。」<br>地圖替『夜燈導航』亮起紅點。<user_nickname>，要接受中山小颱風的叫陣嗎？<br>','中山小颱風：「「橋下陰影是補給，不是休息藉口。」」','','',25.0727,121.535,200,100,25,0,'interval','[{"kind":"warmup","label":"暖身","target_type":"distance","target":1500,"pace_fast_s":399,"pace_slow_s":429,"reps":1,"rest_s":0},{"kind":"work","label":"2000m 間歇","target_type":"distance","target":2000,"pace_fast_s":273,"pace_slow_s":303,"reps":3,"rest_s":200},{"kind":"cooldown","label":"緩和","target_type":"distance","target":1000,"pace_fast_s":399,"pace_slow_s":429,"reps":1,"rest_s":0}]'::jsonb,'gps',5,TRUE),
('DOR-TPE-006','彩虹小潮','彩虹的城市強者關主','臺北市·松山區','彩虹橋／成美左岸河濱','女',36,'耐力折返型',4,'「這裡不看星座，只看分段配速。」','夜燈導航','夜燈導航：彩虹小潮的招牌絕技，讓挑戰者措手不及。','彩虹小潮踏過海堤轉角，鞋上那道水紋剛好把事件畫面切開。<br>彩虹小潮：「先說喔，我沒約人。你是哪位，想相信我真的只是慢跑？」<br>彩虹小潮：「我沒有要認真，除非你先加速。流程聽好：離開起點別急著演英雄；沿亮起的路線跑完一來一回；最後五百公尺才是答卷，看看最後是誰先把這句收回去。」<br>首領事件鎖定彩虹小潮。<user_nickname>，要接受彩虹小潮的叫陣嗎？<br>','彩虹小潮：「「這裡不看星座，只看分段配速。」」','','',25.0505,121.5775,200,80,20,0,'interval','[{"kind":"warmup","label":"暖身","target_type":"distance","target":1500,"pace_fast_s":411,"pace_slow_s":441,"reps":1,"rest_s":0},{"kind":"work","label":"800m 間歇","target_type":"distance","target":800,"pace_fast_s":270,"pace_slow_s":300,"reps":5,"rest_s":120},{"kind":"cooldown","label":"緩和","target_type":"distance","target":1000,"pace_fast_s":411,"pace_slow_s":441,"reps":1,"rest_s":0}]'::jsonb,'gps',6,TRUE),
('DOR-TPE-007','稻埕白鷺姐','稻埕的主線王座關主','臺北市·大同區','大稻埕碼頭／延平河濱','女',24,'長距離巡航型',5,'「逆風不是阻力，是河濱在考你。」','逆風濾鏡','逆風濾鏡：稻埕白鷺姐的招牌絕技，讓挑戰者措手不及。','稻埕白鷺姐先瞄排行榜，再看你的紀錄，笑得像終於找到今天要記住的人。<br>稻埕白鷺姐：「關主雷達剛響就是因為你？來頭講一下，想搶排名還是送一筆戰績？」<br>稻埕白鷺姐：「排行榜空了一格，我可以留給你，但要自己跑來拿。前段先留一點底牌；等你過完最後一個地標才回頭，我再看結果，別想靠嘴巴上榜。」<br>副本入口只剩一個選項。<user_nickname>，要接受稻埕白鷺姐的叫陣嗎？<br>','稻埕白鷺姐：「「逆風不是阻力，是河濱在考你。」」','','',25.0568,121.5084,200,100,25,0,'tempo','[{"kind":"warmup","label":"暖身","target_type":"distance","target":1500,"pace_fast_s":399,"pace_slow_s":429,"reps":1,"rest_s":0},{"kind":"work","label":"節奏跑","target_type":"distance","target":5000,"pace_fast_s":306,"pace_slow_s":336,"reps":1,"rest_s":0},{"kind":"cooldown","label":"緩和","target_type":"distance","target":1000,"pace_fast_s":399,"pace_slow_s":429,"reps":1,"rest_s":0}]'::jsonb,'gps',7,TRUE),
('DOR-TPE-008','萬華小雨衣','華中的區域王牌關主','臺北市·萬華區','華中河濱公園／馬場町','女',50,'長距離巡航型',4,'「萬華的跑道很客氣，我不一定。」','逆風濾鏡','逆風濾鏡：萬華小雨衣的招牌絕技，讓挑戰者措手不及。','任務介面閃過成功兩個字，萬華小雨衣便從橋墩轉過身，手指已經停在挑戰鍵上。<br>萬華小雨衣：「你很面生欸。哪個公會的，想上精華還是上笑話剪輯？」<br>萬華小雨衣：「我平常不太會聊天，開跑就會自動變主持人。先把話說清楚：離開起點別急著演英雄；跑到地圖最外圈才准折返，跟得上我幫你喊；跟不上我也喊，只是內容比較狠。」<br>事件還沒結束。<user_nickname>，要接嗎？<br>','萬華小雨衣：「「萬華的跑道很客氣，我不一定。」」','','',25.0199,121.5046,200,80,20,0,'interval','[{"kind":"warmup","label":"暖身","target_type":"distance","target":1500,"pace_fast_s":411,"pace_slow_s":441,"reps":1,"rest_s":0},{"kind":"work","label":"2000m 間歇","target_type":"distance","target":2000,"pace_fast_s":288,"pace_slow_s":318,"reps":3,"rest_s":200},{"kind":"cooldown","label":"緩和","target_type":"distance","target":1000,"pace_fast_s":411,"pace_slow_s":441,"reps":1,"rest_s":0}]'::jsonb,'gps',8,TRUE),
('DOR-TPE-009','關渡阿階','關渡的菁英支線關主','臺北市·北投區','關渡水岸／關渡宮','男',57,'長距離耐力型',4,'「海風很吵，但你的腳步要更大聲。」','海風迴旋','海風迴旋：關渡阿階的招牌絕技，讓挑戰者措手不及。','你打卡時，關渡阿階正對著坡口微笑，像剛抽到最想要的關卡。<br>關渡阿階：「先等等，這個完成紀錄是你跑的？想進戰術表還是錯誤報告？」<br>關渡阿階：「照片拍完，現在講正事。先把長段跑成完整節奏，讓距離條自己走到滿格；最後五百公尺才是答卷，步頻、呼吸、轉彎都算分；亂跑會被我講很久。」<br>對戰名單剛空出一格。<user_nickname>，要接受關渡阿階的叫陣嗎？<br>','關渡阿階：「「海風很吵，但你的腳步要更大聲。」」','','',25.1245,121.4626,200,80,20,0,'lsd','[{"kind":"warmup","label":"暖身","target_type":"distance","target":1000,"pace_fast_s":411,"pace_slow_s":441,"reps":1,"rest_s":0},{"kind":"steady","label":"長距離 LSD","target_type":"distance","target":10000,"pace_fast_s":408,"pace_slow_s":438,"reps":1,"rest_s":0},{"kind":"cooldown","label":"緩和","target_type":"distance","target":1000,"pace_fast_s":411,"pace_slow_s":441,"reps":1,"rest_s":0}]'::jsonb,'gps',9,TRUE),
('DOR-TPE-010','內湖逆風女王','內湖的城市強者關主','臺北市·內湖區','內湖運動公園','女',25,'恢復跑技巧型',4,'「內湖今天不收觀光客，只收完成者。」','蟬聲加速','蟬聲加速：內湖逆風女王的招牌絕技，讓挑戰者措手不及。','內湖運動公園的任務印記剛亮，內湖逆風女王便抬起挑戰徽章，打卡獎勵旁又多了一個驚嘆號。<br>內湖逆風女王：「新帳號還是隱藏高手？名號丟過來，想碰六分零六的幸運秒數？」<br>內湖逆風女王：「我的碼錶只信六分零六。先記好：開局就把速度放在正確位置，然後維持相同節奏跑滿圈數，節奏守住，我就承認你的運氣有練過。」<br>計時器停在零秒。<user_nickname>，要接受內湖逆風女王的叫陣嗎？<br>','內湖逆風女王：「「內湖今天不收觀光客，只收完成者。」」','','',25.0671,121.5756,120,80,20,0,'easy','[{"kind":"warmup","label":"暖身","target_type":"distance","target":800,"pace_fast_s":411,"pace_slow_s":441,"reps":1,"rest_s":0},{"kind":"steady","label":"輕鬆跑","target_type":"distance","target":5000,"pace_fast_s":390,"pace_slow_s":420,"reps":1,"rest_s":0},{"kind":"cooldown","label":"緩和","target_type":"distance","target":800,"pace_fast_s":411,"pace_slow_s":441,"reps":1,"rest_s":0}]'::jsonb,'gps',10,TRUE),
('DOR-TPE-011','內湖阿虎','大湖的排行榜看門人','臺北市·內湖區','大湖公園','男',32,'節奏跑混合型',4,'「公園很溫柔，但我沒有。」','長椅戰術','長椅戰術：內湖阿虎的招牌絕技，讓挑戰者措手不及。','你完成打卡時，內湖阿虎正替任務找樹擊掌，氣氛莫名正式。<br>內湖阿虎：「我只問一次，你誰啦？想讓鞋子替你證明實力？」<br>內湖阿虎：「這雙鞋的上限很高，你的還不知道。開局先讓腳步進入狀況；等你把整套關卡從頭做到尾，我再看結果，跑完我再給評價。」<br>大湖公園的挑戰令已送到背包。<user_nickname>，要接受內湖阿虎的叫陣嗎？<br>','內湖阿虎：「「公園很溫柔，但我沒有。」」','','',25.0837,121.602,120,80,20,0,'variable','[{"kind":"warmup","label":"暖身","target_type":"distance","target":1200,"pace_fast_s":411,"pace_slow_s":441,"reps":1,"rest_s":0},{"kind":"surge","label":"變速跑 快段 1K","target_type":"distance","target":1000,"pace_fast_s":282,"pace_slow_s":312,"reps":6,"rest_s":120},{"kind":"cooldown","label":"緩和","target_type":"distance","target":1000,"pace_fast_s":411,"pace_slow_s":441,"reps":1,"rest_s":0}]'::jsonb,'gps',11,TRUE),
('DOR-TPE-012','洲美小雀','洲美的在地高手關主','臺北市·北投區','洲美運動公園','男',43,'節奏跑混合型',3,'「你以為是打卡，其實是腿部面試。」','長椅戰術','長椅戰術：洲美小雀的招牌絕技，讓挑戰者措手不及。','你打卡時蟬剛好叫了，洲美小雀像被按下加速鍵一樣轉身。<br>洲美小雀：「欸欸欸，這不是路人能站的位置。你哪位，想照路線跑還是讓我多管？」<br>洲美小雀：「路線我標好了，別說我沒提醒。路線不會替你找理由：把每個任務點都踩到；中途少一段都不算通關，敢開任務就把自己安全帶回來。」<br>關卡資訊全部展開。<user_nickname>，要接受洲美小雀的叫陣嗎？<br>','洲美小雀：「「你以為是打卡，其實是腿部面試。」」','','',25.1037,121.4936,200,60,15,0,'pyramid','[{"kind":"warmup","label":"暖身","target_type":"distance","target":1500,"pace_fast_s":423,"pace_slow_s":453,"reps":1,"rest_s":0},{"kind":"work","label":"金字塔 400m","target_type":"distance","target":400,"pace_fast_s":292,"pace_slow_s":322,"reps":1,"rest_s":0},{"kind":"rest","label":"休息","target_type":"time","target":120,"reps":1,"rest_s":0},{"kind":"work","label":"金字塔 800m","target_type":"distance","target":800,"pace_fast_s":292,"pace_slow_s":322,"reps":1,"rest_s":0},{"kind":"rest","label":"休息","target_type":"time","target":120,"reps":1,"rest_s":0},{"kind":"work","label":"金字塔 1200m","target_type":"distance","target":1200,"pace_fast_s":292,"pace_slow_s":322,"reps":1,"rest_s":0},{"kind":"rest","label":"休息","target_type":"time","target":120,"reps":1,"rest_s":0},{"kind":"work","label":"金字塔 800m","target_type":"distance","target":800,"pace_fast_s":292,"pace_slow_s":322,"reps":1,"rest_s":0},{"kind":"rest","label":"休息","target_type":"time","target":120,"reps":1,"rest_s":0},{"kind":"work","label":"金字塔 400m","target_type":"distance","target":400,"pace_fast_s":292,"pace_slow_s":322,"reps":1,"rest_s":0},{"kind":"cooldown","label":"緩和","target_type":"distance","target":1000,"pace_fast_s":423,"pace_slow_s":453,"reps":1,"rest_s":0}]'::jsonb,'gps',12,TRUE),
